using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable to run this agent.");

const string modelId = "gpt-4o-mini-2024-07-18";

// --- Build the IChatClient via MEAI abstraction ---
IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

// --- Tool state ---
var notebook = new Notebook();
using var httpClient = new HttpClient();
httpClient.DefaultRequestHeaders.UserAgent.ParseAdd("ResearchAgent/1.0");

// --- Define tools ---
var tools = new List<AITool>
{
    AIFunctionFactory.Create(
        [Description("Search the web for information on a query. Returns a list of result snippets.")]
        async (string query) =>
        {
            Console.WriteLine($"  🔍 Searching: \"{query}\"");
            try
            {
                var encoded = Uri.EscapeDataString(query);
                var url = $"https://html.duckduckgo.com/html/?q={encoded}";
                var html = await httpClient.GetStringAsync(url);
                var snippets = ExtractSnippets(html, maxResults: 5);
                return snippets.Count > 0
                    ? string.Join("\n\n", snippets)
                    : "No results found.";
            }
            catch (Exception ex)
            {
                return $"Search failed: {ex.Message}";
            }
        },
        "web_search",
        "Search the web for information on a topic"),

    AIFunctionFactory.Create(
        [Description("Save a research note with a title and content for later reference.")]
        (string title, string content) =>
        {
            notebook.Add(title, content);
            Console.WriteLine($"  📝 Note saved: \"{title}\"");
            return $"Note saved: \"{title}\"";
        },
        "take_note",
        "Save a research note"),

    AIFunctionFactory.Create(
        [Description("Retrieve all saved research notes.")]
        () =>
        {
            var notes = notebook.GetAll();
            if (notes.Count == 0) return "No notes saved yet.";
            return string.Join("\n---\n", notes.Select(n => $"## {n.Title}\n{n.Content}"));
        },
        "get_notes",
        "Retrieve all research notes"),
};

// --- Create the agent ---
var agent = new ChatClientAgent(
    chatClient,
    name: "ResearchAgent",
    description: "An AI agent that researches topics by searching the web and taking notes.",
    instructions: """
        You are a research assistant. When given a topic:
        1. Search the web for relevant information using multiple queries
        2. Take notes on key findings as you discover them
        3. After gathering sufficient information (at least 3 searches), retrieve your notes
        4. Provide a comprehensive summary of your research findings

        Be thorough but focused. Use different search queries to explore various angles of the topic.
        """,
    tools: tools,
    loggerFactory: null,
    serviceProvider: null);

// --- Run the agent ---
Console.WriteLine("╔══════════════════════════════════════╗");
Console.WriteLine("║       AI Research Agent (v1.0)       ║");
Console.WriteLine("╚══════════════════════════════════════╝");
Console.Write("\nEnter a topic to research: ");
var topic = Console.ReadLine()?.Trim();

if (string.IsNullOrWhiteSpace(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\n🔬 Researching: \"{topic}\"\n");

var session = await agent.CreateSessionAsync(
    conversationId: Guid.NewGuid().ToString());

var runOptions = new ChatClientAgentRunOptions
{
    ChatOptions = new ChatOptions
    {
        Temperature = 0f,
        MaxOutputTokens = 4096,
    },
};

var response = await agent.RunAsync(
    $"Research the following topic and provide a detailed summary: {topic}",
    session,
    runOptions,
    CancellationToken.None);

Console.WriteLine("\n════════════════════════════════════════");
Console.WriteLine("📋 RESEARCH SUMMARY");
Console.WriteLine("════════════════════════════════════════\n");

foreach (var message in response.Messages.Where(m => m.Role == ChatRole.Assistant))
{
    var text = message.Text;
    if (!string.IsNullOrWhiteSpace(text))
        Console.WriteLine(text);
}

Console.WriteLine($"\n✅ Research complete. {notebook.GetAll().Count} notes taken.");

// --- Helper: Extract snippets from DuckDuckGo HTML ---
static List<string> ExtractSnippets(string html, int maxResults)
{
    var snippets = new List<string>();
    var searchToken = "class=\"result__snippet\"";
    var index = 0;

    while (snippets.Count < maxResults)
    {
        index = html.IndexOf(searchToken, index, StringComparison.Ordinal);
        if (index < 0) break;

        var start = html.IndexOf('>', index) + 1;
        var end = html.IndexOf('<', start);
        if (start > 0 && end > start)
        {
            var snippet = System.Net.WebUtility.HtmlDecode(
                html[start..end].Trim());
            if (!string.IsNullOrWhiteSpace(snippet))
                snippets.Add(snippet);
        }
        index = end > 0 ? end : index + 1;
    }

    return snippets;
}

// --- Notebook class ---
class Notebook
{
    private readonly List<Note> _notes = [];

    public void Add(string title, string content) =>
        _notes.Add(new Note(title, content));

    public IReadOnlyList<Note> GetAll() => _notes.AsReadOnly();
}

record Note(string Title, string Content);

