// --- Helper: Extract snippets from DuckDuckGo HTML ---
static List<string> ExtractSnippets(string html, int maxResults)
{
    var snippets = new List<string>();
    var searchToken = "class=\"result__snippet\"";
    var index = 0;

    while (snippets.Count < maxResults)
    {
        index = html.IndexOf(searchToken, index, StringComparison.Ordinal);
        if (index < 0) break;

        var start = html.IndexOf('>', index) + 1;
        var end = html.IndexOf('<', start);
        if (start > 0 && end > start)
        {
            var snippet = System.Net.WebUtility.HtmlDecode(
                html[start..end].Trim());
            if (!string.IsNullOrWhiteSpace(snippet))
                snippets.Add(snippet);
        }
        index = end > 0 ? end : index + 1;
    }

    return snippets;
}

